// Template: photobooth-animation-1
// Description: No description available
// Scene: Scene 1

import { AbsoluteFill, spring, interpolate, useCurrentFrame, useVideoConfig, Img, Audio, Sequence, Loop, OffthreadVideo } from "remotion";
import React from "react";

const SCENE_PARAMS = {
  backgroundColor: { type: "color", label: "Background", value: "#eabec9" },
  slotColor: { type: "color", label: "Slot Frame", value: "#E8E8E8" },
  paperColor: { type: "color", label: "Paper", value: "#FAFAFA" },
  textColor: { type: "color", label: "Text Color", value: "#1a1a1a" },
  scale: { type: "number", label: "Scale", value: 1, min: 0.5, max: 2, step: 0.05 },
  animationSpeed: { type: "number", label: "Animation Speed", value: 1, min: 0.5, max: 2, step: 0.1 },
  verticalPosition: { type: "number", label: "Vertical Position", value: 0.19, min: 0.05, max: 0.5, step: 0.05 },
  dateText: { type: "text", label: "Date", value: "01.15.2024" },
  timeText: { type: "text", label: "Time", value: "14:32" },
  photo1: { type: "image", label: "Photo 1", value: "https://miuzeaacksoumruaqxfv.supabase.co/storage/v1/object/public/input/template-1770879986061-p6x5t5j/photo4_2.png" },
  photo2: { type: "image", label: "Photo 2", value: "https://miuzeaacksoumruaqxfv.supabase.co/storage/v1/object/public/input/template-1770879986061-p6x5t5j/photo4_3.png" },
  photo3: { type: "image", label: "Photo 3", value: "data:image/png;base64," },
  showStripes: { type: "boolean", label: "Show Wood Grain", value: true },
};

function Scene() {
  const frame = useCurrentFrame();
  const { fps, width, height } = useVideoConfig();
  
  const minDim = Math.min(width, height);
  const speed = SCENE_PARAMS.animationSpeed.value;
  const scaleValue = SCENE_PARAMS.scale.value;
  const verticalPos = SCENE_PARAMS.verticalPosition.value;
  
  const printDuration = 150;
  const adjustedFrame = frame * speed;
  
  let paperProgress = 0;
  if (adjustedFrame < printDuration) {
    const baseProgress = adjustedFrame / printDuration;
    const steps = 30;
    const stepped = Math.floor(baseProgress * steps) / steps;
    const stepFrame = adjustedFrame % (printDuration / steps);
    const smooth = interpolate(stepFrame, [0, (printDuration / steps) * 0.7], [0, 1 / steps], { extrapolateRight: "clamp" });
    paperProgress = Math.min(stepped + smooth * 0.5, 1);
  } else {
    paperProgress = 1;
  }
  
  const dispenserWidth = minDim * 0.7;
  const dispenserHeight = minDim * 0.12;
  const slotWidth = dispenserWidth * 0.8;
  const slotHeight = minDim * 0.015;
  const paperWidth = minDim * 0.55 * 0.75 * 0.85;
  
  const photoStripPadding = minDim * 0.03;
  const photoWidth = paperWidth - photoStripPadding * 2;
  const photoHeight = photoWidth * 1.15;
  const photoGap = minDim * 0.02;
  const paddingTop = minDim * 0.035;
  const dateTimeHeight = minDim * 0.04;
  
  const maxPaperHeight = paddingTop + 3 * photoHeight + 2 * photoGap + photoStripPadding + dateTimeHeight + photoStripPadding;
  const currentPaperHeight = maxPaperHeight * paperProgress;
  
  const curlAmount = paperProgress * 2;
  
  const stripeCount = 40;
  const stripes = [];
  if (SCENE_PARAMS.showStripes.value) {
    for (let i = 0; i < stripeCount; i++) {
      const x = (i / stripeCount) * 100;
      const opacity = 0.15 + Math.sin(i * 0.7) * 0.1;
      stripes.push(
        React.createElement("div", {
          key: i,
          style: {
            position: "absolute",
            left: x + "%",
            top: 0,
            width: 2,
            height: "100%",
            backgroundColor: "#000",
            opacity: opacity,
          }
        })
      );
    }
  }
  
  const photos = [
    { image: SCENE_PARAMS.photo1.value, fallbackColor: "#4a5568" },
    { image: SCENE_PARAMS.photo2.value, fallbackColor: "#5a6778" },
    { image: SCENE_PARAMS.photo3.value, fallbackColor: "#3a4558" },
  ];
  
  const clipHeight = currentPaperHeight;
  
  const photoElements = photos.map((photo, i) => {
    const photoY = paddingTop + i * (photoHeight + photoGap);
    
    const hasImage = photo.image && photo.image.length > 0;
    
    return React.createElement("div", {
      key: i,
      style: {
        position: "absolute",
        top: photoY,
        left: photoStripPadding,
        width: photoWidth,
        height: photoHeight,
        overflow: "hidden",
      }
    },
      hasImage 
        ? React.createElement(Img, {
            src: photo.image,
            style: {
              width: "100%",
              height: "100%",
              objectFit: "cover",
              display: "block",
            }
          })
        : React.createElement("div", {
            style: {
              width: "100%",
              height: "100%",
              backgroundColor: photo.fallbackColor,
              display: "flex",
              justifyContent: "center",
              alignItems: "center",
              position: "relative",
              overflow: "hidden",
            }
          },
            React.createElement("div", {
              style: {
                fontSize: minDim * 0.025,
                color: "rgba(255,255,255,0.5)",
                fontFamily: "system-ui, sans-serif",
                textAlign: "center",
              }
            }, "Upload Photo " + (i + 1))
          )
    );
  });
  
  const dateTimeY = paddingTop + 3 * (photoHeight + photoGap) - photoGap + photoStripPadding;
  
  return React.createElement(AbsoluteFill, {
    style: {
      backgroundColor: SCENE_PARAMS.backgroundColor.value,
      justifyContent: "flex-start",
      alignItems: "center",
      overflow: "hidden",
    }
  },
    React.createElement("div", {
      style: {
        position: "absolute",
        inset: 0,
        overflow: "hidden",
      }
    }, stripes),
    
    React.createElement("div", {
      style: {
        position: "absolute",
        inset: 0,
        background: "repeating-linear-gradient(90deg, transparent, transparent 25px, rgba(0,0,0,0.08) 25px, rgba(0,0,0,0.08) 27px)",
      }
    }),
    
    React.createElement("div", {
      style: {
        transform: "scale(" + scaleValue + ")",
        transformOrigin: "center top",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        position: "relative",
        marginTop: height * verticalPos,
      }
    },
      currentPaperHeight > 0 && React.createElement("div", {
        style: {
          position: "absolute",
          top: dispenserHeight * 0.5 - minDim * 0.01,
          width: paperWidth,
          height: currentPaperHeight,
          backgroundColor: SCENE_PARAMS.paperColor.value,
          borderRadius: "0 0 " + minDim * 0.003 + "px " + minDim * 0.003 + "px",
          boxShadow: "2px 4px 15px rgba(0,0,0,0.25), -1px 0 3px rgba(0,0,0,0.1)",
          overflow: "hidden",
          zIndex: 20,
          transform: "perspective(" + minDim + "px) rotateX(" + (-curlAmount) + "deg)",
          transformOrigin: "top center",
        }
      },
        React.createElement("div", {
          style: {
            position: "absolute",
            inset: 0,
            background: "repeating-linear-gradient(0deg, transparent, transparent 3px, rgba(0,0,0,0.02) 3px, rgba(0,0,0,0.02) 4px)",
          }
        }),
        
        React.createElement("div", {
          style: {
            position: "relative",
            width: "100%",
            height: maxPaperHeight,
            clipPath: "inset(0 0 " + (maxPaperHeight - clipHeight) + "px 0)",
          }
        },
          ...photoElements,
          
          React.createElement("div", {
            style: {
              position: "absolute",
              top: dateTimeY,
              left: 0,
              right: 0,
              textAlign: "center",
            }
          },
            React.createElement("div", {
              style: {
                fontFamily: "'Courier New', monospace",
                fontSize: minDim * 0.022,
                fontWeight: 500,
                color: SCENE_PARAMS.textColor.value,
                letterSpacing: 2,
              }
            }, SCENE_PARAMS.dateText.value + " • " + SCENE_PARAMS.timeText.value)
          )
        ),
        
        React.createElement("div", {
          style: {
            position: "absolute",
            bottom: 0,
            left: 0,
            right: 0,
            height: minDim * 0.008,
            background: "linear-gradient(90deg, " + 
              Array(20).fill(0).map(function(_, i) {
                return SCENE_PARAMS.paperColor.value + " " + (i * 5) + "%, transparent " + (i * 5 + 2) + "%";
              }).join(", ") + ")",
            opacity: paperProgress > 0.9 ? 1 : 0,
          }
        })
      ),
      
      React.createElement("div", {
        style: {
          position: "relative",
          width: dispenserWidth,
          height: dispenserHeight,
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          zIndex: 10,
        }
      },
        React.createElement("div", {
          style: {
            position: "absolute",
            width: slotWidth + minDim * 0.08,
            height: dispenserHeight,
            backgroundColor: SCENE_PARAMS.slotColor.value,
            borderRadius: minDim * 0.015,
            boxShadow: "0 4px 20px rgba(0,0,0,0.4), inset 0 2px 4px rgba(255,255,255,0.3)",
          }
        }),
        
        React.createElement("div", {
          style: {
            position: "absolute",
            width: slotWidth,
            height: dispenserHeight * 0.6,
            backgroundColor: "#1a1a1a",
            borderRadius: minDim * 0.008,
            boxShadow: "inset 0 3px 10px rgba(0,0,0,0.8)",
          }
        }),
        
        React.createElement("div", {
          style: {
            position: "absolute",
            width: slotWidth * 0.9,
            height: slotHeight,
            backgroundColor: "#0a0a0a",
            borderRadius: slotHeight / 2,
            boxShadow: "inset 0 2px 5px rgba(0,0,0,0.9)",
          }
        })
      )
    )
  );
}

export default Scene;
